        int[] count = new int[10];
        String[] str = {"zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine"};
        String[] charCount = {"z", "w", "t", "u", "f", "s", "s", "n", "e", "r"};
        for (int i = 0; i < 10; i++) {
            for (int j = 0; j < s.length(); j++) {
                if (s.charAt(j) == charCount[i].charAt(0)) {
                    count[i]++;
                }
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 10; i++) {
            while (count[i] > 0) {
                sb.append(i);
                count[i]--;
            }
        }
        return sb.toString();
    }
